  ('aboriginal-f0899a01-moex-00577', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '原住民保留地開發管理辦法第27條中規定，第23條至第25條之原住民保留地承租人有特定情形者， 應終止租約收回土地，其所投資之各項設施不予補償。以下所述何者不屬這些特定情形？', '["經原住民保留地土地權利審查委員會提案並通過終止租約者", "違反計畫使用者", "轉租或由他人頂替者", "未依開發或興辦計畫開發或興辦，且未報經核准變更計畫或展延開發、興辦期限者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00578', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '根據人體研究法第15條，以研究原住民族為目的者，除依第12條至第14條規定外，並應諮詢、取 得各該原住民族之同意，而根據原住民族委員會所訂定之人體研究計畫諮詢取得原住民族同意與約定 商業利益及其應用辦法之定義，「以研究原住民族為目的者」不包含以下那一項？', '["以原住民族或部落為研究內容", "研究檢體之採集、研究資料之搜集及分析涉及原住民族或部落", "研究結果之解釋涉及原住民族或部落", "研究團隊之成員三分之一以上為原住民"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00579', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '根據推動原住民族法律服務要點第5點，具「依申請人之陳述及所提資料，顯無理由」，或是「訴訟 所可能獲得之利益，小於律師酬金」之情形者，不予服務。但如涉及下列那些情形者，仍得予提供法 律服務？', '["原住民族傳統慣習、原住民族基本權利與國家法令、司法程序衝突", "同一申請人自准予扶助起1年內，依第3點第4款准予扶助達3次", "申請人為其住所地直轄市、縣（市）主管機關審核認定之社會救助法中低收入戶", "申請人具公務人員身分，且涉及公職人員選舉罷免事件相關之民事訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
